import { gs, GlideDateTime } from '@servicenow/glide';
export function validateLifecycleRequest(current, previous) {
    const requestType = current.getValue('request_type');
    const today = new GlideDateTime();
    if (requestType === 'onboarding') {
        const joiningDate = current.getValue('joining_date');
        if (joiningDate) {
            const joinGDT = new GlideDateTime(joiningDate);
            if (joinGDT.before(today)) {
                gs.addErrorMessage('Joining date cannot be in the past');
                current.setAbortAction(true);
            }
        }
    }
    else if (requestType === 'offboarding') {
        const exitDate = current.getValue('exit_date');
        if (exitDate) {
            const exitGDT = new GlideDateTime(exitDate);
            if (exitGDT.before(today)) {
                gs.addErrorMessage('Exit date cannot be in the past');
                current.setAbortAction(true);
            }
        }
    }
}
